SELECT
    A.LSN_NUM, A.CLA_NUM, A.LSN_SEQ, A.LSN_TITLE, A.LSN_CONTENT,
    B.LA_SAVE_NAME, C.CLA_TITLE
FROM LESSON A
LEFT JOIN LESSON_ATTACH B ON A.LSN_NUM = B.LSN_NUM AND B.LA_TYPE = 'VIDEO'
JOIN CLASS C ON A.CLA_NUM = C.CLA_NUM
WHERE A.CLA_NUM = #{claNum, jdbcType=VARCHAR}

    
        AND A.LSN_NUM = #{lsnNum}
    
    
        AND A.LSN_SEQ = #{lsnSeq}

SELECT LSN_NUM FROM (
    SELECT LSN_NUM FROM LESSON 
    WHERE CLA_NUM = #{claNum} 
    ORDER BY LSN_SEQ ASC
) WHERE ROWNUM = 1

SELECT LSN_NUM FROM (
    SELECT LSN_NUM FROM LESSON 
    WHERE CLA_NUM = #{claNum, jdbcType=VARCHAR} 
      AND LSN_SEQ < (SELECT LSN_SEQ FROM LESSON WHERE LSN_NUM = #{lsnNum, jdbcType=VARCHAR})
    ORDER BY LSN_SEQ DESC
) WHERE ROWNUM = 1

SELECT LSN_NUM FROM (
    SELECT LSN_NUM FROM LESSON 
    WHERE CLA_NUM = #{claNum, jdbcType=VARCHAR} 
      AND LSN_SEQ > (SELECT LSN_SEQ FROM LESSON WHERE LSN_NUM = #{lsnNum, jdbcType=VARCHAR})
    ORDER BY LSN_SEQ ASC
) WHERE ROWNUM = 1
